const items = $input.all();
const output = [];

for (const item of items) {
  const payload = item.json.content?.payload || {};

  if (!payload || Object.keys(payload).length === 0) {
    output.push({
      json: {
        key: "status",
        value: "1",
      },
    });
    continue;
  }

  for (const [key, value] of Object.entries(payload)) {
    output.push({
      json: {
        key,
        value,
      },
    });
  }
}

return output;

const items = $input.all();

const STATUS_LABEL = {
  1: 'Aberta',
  2: 'Em andamento',
  3: 'Concluída',
  4: 'Cancelada',
};

// const orders = items[0].json.data || []
const orders = items[0].json.data?.orders || [];

function formatDate(dateString) {
  if (!dateString) return '-';

  const date = new Date(dateString);

  if (isNaN(date)) return dateString;

  return date.toLocaleString('pt-BR', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
}

if (!orders.length) {
  return [
    {
      json: {
        message:
          'Não encontrei nenhuma ordem de serviço. Como posso te ajudar?',
      },
    },
  ];
}

let message = '*Suas ordens de serviço*\n\n';

for (const order of orders) {
  // const order = item.json;
  const statusTraduzido =
    STATUS_LABEL[order.status] ?? order.status ?? '-';

  const dataFormatada = formatDate(order.createdAt);

  message +=
    '━━━━━━━━━━━━━━━\n' +
    `🔢 Número: #${order.number ?? '-'}\n` +
    `📌 Situação: ${statusTraduzido}\n` +
    `👤 Cliente: ${order.client ?? '-'}\n` +
    `🚗 Veículo: ${order.vehicle ?? '-'}\n` +
    `🛠️ Serviço: ${order.description ?? '-'}\n` +
    `📅 Criada em: ${dataFormatada}\n`;
}

message += '━━━━━━━━━━━━━━━';

return [
  {
    json: {
      message,
      total: orders.length,
    },
  },
];

const items = $input.all();
const payload = items[0].json.content.payload;

const number = payload.number ?? "Não informado";
const data = payload.data ?? {};

const statusMap = {
  1: "Aberta",
  2: "Em andamento",
  3: "Concluída",
  4: "Cancelada"
};

let changes = [];

if (data.client) {
  changes.push(`👤 Cliente: ${data.client}`);
}

if (data.vehicle) {
  changes.push(`🚗 Veículo: ${data.vehicle}`);
}

if (data.description) {
  changes.push(`📝 Serviço: ${data.description}`);
}

if (data.status) {
  changes.push(`📊 Status: ${statusMap[data.status] ?? data.status}`);
}

const resumo = `Alteração na OS #${number}:

${changes.join("\n")}`;

return [
  {
    json: {
      ...items,
      resumo
    }
  }
];

